// All of these produce: "React Hook 'X' is called conditionally."
// React Hooks must be called in the exact same order in every component render.

// ✗ Conditional
function A({ show }) {
  if (show) { const [x] = useState(0); }  // ERROR
}

// ✗ Loop
function B({ items }) {
  for (const i of items) {
    useEffect(() => console.log(i), [i]);  // ERROR
  }
}

// ✗ After early return
function C({ ready }) {
  if (!ready) return null;
  const [x] = useState(0);  // ERROR — hook after return
}

// ✗ Non-React function
function formatDate(d) {
  const fmt = useMemo(() => new Intl.DateTimeFormat(), []);  // ERROR
  return fmt.format(d);
}

// ✗ Missing dep — stale closure bug
function UserCard({ userId }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    fetch(`/api/users/${userId}`)  // userId used but not in deps
      .then(r => r.json())
      .then(setUser);
  }, []);  // WARN: React Hook useEffect has a missing dependency: 'userId'
  // Bug: effect runs once with the initial userId and never re-fetches

  return <div>{user?.name}</div>;
}

// ✓ Fixed — add the dep
function UserCard({ userId }) {
  const [user, setUser] = useState(null);
  useEffect(() => {
    fetch(`/api/users/${userId}`).then(r => r.json()).then(setUser);
  }, [userId]);  // re-fetches whenever userId changes
  return <div>{user?.name}</div>;
}

// ✗ Extra dep — unnecessary re-runs
function Timer() {
  const [count, setCount] = useState(0);
  useEffect(() => {
    const id = setInterval(() => setCount(c => c + 1), 1000);
    return () => clearInterval(id);
  }, [count]);  // WARN: 'count' is not used inside the effect
  // count is not referenced in the body — including it causes
  // the interval to be reset on every count change (unintended)

  return <div>{count}</div>;
}

function Counter() {
  const [count, setCount] = useState(0);
  const ref = useRef(null);

  useEffect(() => {
    // setCount is stable — safe to omit from deps (linter knows this)
    const id = setInterval(() => setCount(c => c + 1), 1000);
    // ref is stable — safe to omit
    ref.current?.scrollIntoView();
    return () => clearInterval(id);
  }, []);  // no warning — setCount and ref are stable by guarantee
  // ref.current is NOT stable — reading it inside deps creates subtle bugs
}

// Pattern 1: add dep (most common)
useEffect(() => { fetch(url).then(setData); }, [url]);

// Pattern 2: ref for values that should not trigger re-run
function useLatest(value) {
  const ref = useRef(value);
  useLayoutEffect(() => { ref.current = value; }); // sync after render
  return ref;
}
function Search({ onResult }) {
  const onResultRef = useLatest(onResult); // stable ref to latest callback
  useEffect(() => {
    search().then(data => onResultRef.current(data)); // no dep on onResult
  }, []); // empty deps — effect runs once, always calls latest onResult
}

// Pattern 3: updater form to remove state dep
useEffect(() => {
  const id = setInterval(() => setCount(c => c + 1), 1000); // no count dep
  return () => clearInterval(id);
}, []);

// Suppress rules-of-hooks for a runtime-constant condition
// eslint-disable-next-line react-hooks/rules-of-hooks
const [debug, setDebug] = useState(false); // only valid if condition is truly constant

// Suppress exhaustive-deps when the omission is intentional
useEffect(() => {
  logger.log(latestValue); // intentionally reads latest via ref pattern
  // eslint-disable-next-line react-hooks/exhaustive-deps
}, [trigger]); // latestValue omitted intentionally — read via ref above

// Never suppress without a comment explaining why:
// ✗ Bad — silent suppression gives no context
// eslint-disable-next-line react-hooks/exhaustive-deps
useEffect(() => { doWork(value); }, []);

// eslint.config.js (flat config)
import reactHooks from 'eslint-plugin-react-hooks';

export default [
  {
    plugins: {
      'react-hooks': reactHooks,
    },
    rules: {
      'react-hooks/rules-of-hooks': 'error',
      'react-hooks/exhaustive-deps': 'warn',
    },
  },
];

// .eslintrc.json — register custom hooks for exhaustive-deps analysis
{
  "rules": {
    "react-hooks/exhaustive-deps": ["warn", {
      "additionalHooks": "(useMyEffect|useEventCallback|useStableCallback)"
    }]
  }
}

// Now the linter checks deps arrays in these custom hooks too:
function Component({ value, onChange }) {
  useMyEffect(() => {
    doWork(value);
  }, [value]);  // exhaustive-deps applied here — warns if value is missing
}

// ✗ Adding the missing dep causes an infinite loop
function Component({ config }) {
  const [data, setData] = useState(null);

  // config is { url: '/api/data' } — a new object on every render
  useEffect(() => {
    fetch(config.url).then(r => r.json()).then(setData);
  }, [config]); // config is new every render → effect runs → re-render → new config → ...
}

// ✓ Fix 1: depend on primitive values inside the object
function Component({ config }) {
  const { url } = config;
  useEffect(() => {
    fetch(url).then(r => r.json()).then(setData);
  }, [url]); // url is a string — stable if the value doesn't change
}

// ✓ Fix 2: memoize the object so its reference is stable
function Component({ url, headers }) {
  const config = useMemo(() => ({ url, headers }), [url, headers]);
  useEffect(() => {
    fetch(config.url, { headers: config.headers }).then(...);
  }, [config]); // stable reference — effect only re-runs when url or headers change
}

// ✗ Inline object dep — effect runs on every render
function Chart({ width, height, color }) {
  useEffect(() => {
    draw({ width, height, color }); // options object used
  }, [{ width, height, color }]);  // new object reference every render
}

// ✓ Depend on primitives, not the wrapper object
function Chart({ width, height, color }) {
  useEffect(() => {
    draw({ width, height, color });
  }, [width, height, color]); // primitive values — stable when unchanged
}

// ✗ Inline function dep — re-runs on every render
function Feed({ userId }) {
  useEffect(() => {
    // onLoad is captured at render time — new reference every render
    subscribe(userId, (data) => console.log(data));
  }, [userId, (data) => console.log(data)]); // anonymous fn = always new
}

// ✓ Use useCallback to stabilize the function reference
function Feed({ userId }) {
  const handleData = useCallback((data) => {
    console.log(data);
  }, []);  // empty deps — function has no outer dependencies

  useEffect(() => {
    subscribe(userId, handleData);
    return () => unsubscribe(userId, handleData);
  }, [userId, handleData]); // handleData is now stable
}
